use std::fs;
use std::path::{Path, PathBuf};

use anyhow::{bail, Context, Result};
use clap::Parser;

use connectanum_bench_orchestrator::artifacts::{
    evaluate_artifact_gate, load_artifact_bundle, load_artifact_gate_policy,
    render_artifact_gate_markdown, ArtifactGatePolicy,
};

#[derive(Parser, Debug)]
#[command(
    author,
    version,
    about = "Fail when transformed bench artifacts capture transport or performance regressions"
)]
struct Args {
    /// Input summary JSON generated by transform_results/http_stream.
    #[arg(
        long,
        default_value = "native/bench/artifacts/bench_results.summary.json"
    )]
    summary: PathBuf,

    /// Optional explicit JSON report output path.
    #[arg(long)]
    report_json: Option<PathBuf>,

    /// Optional explicit Markdown report output path.
    #[arg(long)]
    report_md: Option<PathBuf>,

    /// Optional JSON policy with scoped counter and performance thresholds.
    #[arg(long)]
    policy: Option<PathBuf>,
}

fn main() -> Result<()> {
    let args = Args::parse();
    let summary = load_artifact_bundle(&args.summary)?;
    let policy = match args.policy.as_ref() {
        Some(path) => load_artifact_gate_policy(path)?,
        None => ArtifactGatePolicy::default(),
    };
    let report = evaluate_artifact_gate(&summary, &args.summary, &policy);

    let report_json_path = args
        .report_json
        .unwrap_or_else(|| sibling_gate_report_path(&args.summary, "json"));
    let report_md_path = args
        .report_md
        .unwrap_or_else(|| sibling_gate_report_path(&args.summary, "md"));

    if let Some(parent) = report_json_path.parent() {
        fs::create_dir_all(parent)
            .with_context(|| format!("failed to create {}", parent.display()))?;
    }
    if let Some(parent) = report_md_path.parent() {
        fs::create_dir_all(parent)
            .with_context(|| format!("failed to create {}", parent.display()))?;
    }

    let report_json =
        serde_json::to_vec_pretty(&report).context("failed to encode gate report JSON")?;
    fs::write(&report_json_path, report_json)
        .with_context(|| format!("failed to write {}", report_json_path.display()))?;

    let report_md = render_artifact_gate_markdown(&report);
    fs::write(&report_md_path, report_md)
        .with_context(|| format!("failed to write {}", report_md_path.display()))?;

    println!("Wrote {}", report_json_path.display());
    println!("Wrote {}", report_md_path.display());

    if report.failed() {
        for finding in &report.findings {
            println!(
                "[{:?}] {}/{}/{} client={} router_workers={} native_runtime_threads={} kind={} observed={} threshold={}",
                finding.severity,
                finding.scenario,
                finding.workload,
                finding.protocol,
                finding.client_impl,
                finding.router_workers,
                native_runtime_threads_label(finding.native_runtime_threads),
                finding.kind,
                finding.observed,
                finding.threshold,
            );
        }
        for finding in &report.metric_findings {
            println!(
                "[{:?}] {}/{}/{} client={} router_workers={} native_runtime_threads={} metric={} observed={:.3} threshold={:.3} comparison={:?}",
                finding.severity,
                finding.scenario,
                finding.workload,
                finding.protocol,
                finding.client_impl,
                finding.router_workers,
                native_runtime_threads_label(finding.native_runtime_threads),
                finding.kind,
                finding.observed,
                finding.threshold,
                finding.comparison,
            );
        }
        bail!(
            "bench artifact gate failed with {} finding(s)",
            report.finding_count()
        );
    }

    println!(
        "Bench artifact gate passed for {} workload(s).",
        report.workload_count
    );
    Ok(())
}

fn sibling_gate_report_path(summary_path: &Path, extension: &str) -> PathBuf {
    let file_name = summary_path
        .file_name()
        .and_then(|name| name.to_str())
        .unwrap_or("bench_results.summary.json");
    let stem = file_name
        .strip_suffix(".summary.json")
        .or_else(|| file_name.strip_suffix(".json"))
        .unwrap_or(file_name);
    summary_path.with_file_name(format!("{stem}.gate.{extension}"))
}

fn native_runtime_threads_label(value: u32) -> String {
    if value == 0 {
        "auto".to_string()
    } else {
        value.to_string()
    }
}
